-- Create tables
CREATE TABLE IF NOT EXISTS todos (
    id SERIAL PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id),
    title TEXT NOT NULL,
    completed BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMP DEFAULT NOW()
);

-- Create anon role for unauthenticated access
CREATE ROLE anon NOLOGIN;
GRANT USAGE ON SCHEMA public TO anon;
GRANT SELECT ON ALL TABLES IN SCHEMA public TO anon;

-- Create authenticated role
CREATE ROLE authenticated NOLOGIN;
GRANT USAGE ON SCHEMA public TO authenticated;
GRANT ALL ON ALL TABLES IN SCHEMA public TO authenticated;
GRANT USAGE ON ALL SEQUENCES IN SCHEMA public TO authenticated;

-- Enable RLS
ALTER TABLE todos ENABLE ROW LEVEL SECURITY;

-- RLS policies
CREATE POLICY "Users can only see their own todos" ON todos
    FOR ALL
    USING (user_id = auth.uid());

// API client for PostgREST
const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:3001';

export async function getTodos() {
  const res = await fetch(`${API_URL}/todos`);
  return res.json();
}

export async function createTodo(title: string) {
  const res = await fetch(`${API_URL}/todos`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ title }),
  });
  return res.json();
}

export async function updateTodo(id: number, completed: boolean) {
  const res = await fetch(`${API_URL}/todos?id=eq.${id}`, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ completed }),
  });
  return res.json();
}

export async function deleteTodo(id: number) {
  const res = await fetch(`${API_URL}/todos?id=eq.${id}`, {
    method: 'DELETE',
  });
  return res.ok;
}

// Auth client using Supabase JS (compatible with GoTrue)
import { createClient } from '@supabase/supabase-js';

const supabaseUrl = import.meta.env.VITE_AUTH_URL || 'http://localhost:9999';
const supabaseKey = 'anon-key';

export const supabase = createClient(supabaseUrl, supabaseKey);

export async function signUp(email: string, password: string) {
  const { data, error } = await supabase.auth.signUp({
    email,
    password,
  });
  return { data, error };
}

export async function signIn(email: string, password: string) {
  const { data, error } = await supabase.auth.signInWithPassword({
    email,
    password,
  });
  return { data, error };
}

export async function signOut() {
  await supabase.auth.signOut();
}

export function getUser() {
  return supabase.auth.getUser();
}

export function onAuthStateChange(callback: (event: string, session: any) => void) {
  return supabase.auth.onAuthStateChange(callback);
}

// Storage client for MinIO (S3-compatible)
const STORAGE_URL = import.meta.env.VITE_STORAGE_URL || 'http://localhost:9000';

export async function uploadFile(file: File, bucket: string = 'uploads') {
  const formData = new FormData();
  formData.append('file', file);

  const res = await fetch(`${STORAGE_URL}/${bucket}/${file.name}`, {
    method: 'PUT',
    body: file,
  });

  if (!res.ok) throw new Error('Upload failed');
  return `${STORAGE_URL}/${bucket}/${file.name}`;
}

export function getFileUrl(path: string, bucket: string = 'uploads') {
  return `${STORAGE_URL}/${bucket}/${path}`;
}

import { useEffect, useState } from 'react';
import { getTodos, createTodo, updateTodo, deleteTodo } from './lib/api';
import { signIn, signUp, signOut, getUser, onAuthStateChange } from './lib/auth';
import './App.css';

function App() {
  const [todos, setTodos] = useState([]);
  const [newTodo, setNewTodo] = useState('');
  const [user, setUser] = useState(null);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  useEffect(() => {
    loadTodos();
    checkUser();

    const { data: { subscription } } = onAuthStateChange((event, session) => {
      setUser(session?.user || null);
    });

    return () => subscription.unsubscribe();
  }, []);

  async function loadTodos() {
    const data = await getTodos();
    setTodos(data);
  }

  async function checkUser() {
    const { data: { user } } = await getUser();
    setUser(user);
  }

  async function handleAddTodo(e: React.FormEvent) {
    e.preventDefault();
    if (!newTodo.trim()) return;
    await createTodo(newTodo);
    setNewTodo('');
    loadTodos();
  }

  async function handleSignUp(e: React.FormEvent) {
    e.preventDefault();
    await signUp(email, password);
    alert('Check your email!');
  }

  async function handleSignIn(e: React.FormEvent) {
    e.preventDefault();
    await signIn(email, password);
  }

  async function handleSignOut() {
    await signOut();
    setUser(null);
  }

  if (!user) {
    return (
      <div className="App">
        <h1>Easyploy Standard</h1>
        <form onSubmit={handleSignIn}>
          <input
            type="email"
            placeholder="Email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
          <button type="submit">Sign In</button>
          <button type="button" onClick={handleSignUp}>Sign Up</button>
        </form>
      </div>
    );
  }

  return (
    <div className="App">
      <header>
        <h1>Easyploy Standard</h1>
        <span>Welcome, {user.email}</span>
        <button onClick={handleSignOut}>Sign Out</button>
      </header>

      <form onSubmit={handleAddTodo}>
        <input
          value={newTodo}
          onChange={(e) => setNewTodo(e.target.value)}
          placeholder="Add a todo..."
        />
        <button type="submit">Add</button>
      </form>

      <ul>
        {todos.map((todo: any) => (
          <li key={todo.id}>
            <input
              type="checkbox"
              checked={todo.completed}
              onChange={() => updateTodo(todo.id, !todo.completed).then(loadTodos)}
            />
            <span style={{ textDecoration: todo.completed ? 'line-through' : 'none' }}>
              {todo.title}
            </span>
            <button onClick={() => deleteTodo(todo.id).then(loadTodos)}>Delete</button>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default App;

#!/usr/bin/env node

// MCP Server for easyploy-standard
// Provides AI access to database, auth, and storage

import { Server } from '@modelcontextprotocol/sdk/server/index.js';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
import { CallToolRequestSchema, ListToolsRequestSchema } from '@modelcontextprotocol/sdk/types.js';

const server = new Server(
  { name: 'easyploy-standard', version: '1.0.0' },
  { capabilities: { tools: {} } }
);

const tools = [
  {
    name: 'query_database',
    description: 'Execute SQL query on PostgreSQL',
    inputSchema: {
      type: 'object',
      properties: {
        query: { type: 'string', description: 'SQL query' },
      },
      required: ['query'],
    },
  },
  {
    name: 'create_record',
    description: 'Create a record via PostgREST API',
    inputSchema: {
      type: 'object',
      properties: {
        table: { type: 'string' },
        data: { type: 'object' },
      },
      required: ['table', 'data'],
    },
  },
  {
    name: 'upload_file',
    description: 'Upload file to MinIO storage',
    inputSchema: {
      type: 'object',
      properties: {
        path: { type: 'string' },
        content: { type: 'string' },
      },
      required: ['path', 'content'],
    },
  },
  {
    name: 'auth_user',
    description: 'Get current user info',
    inputSchema: {
      type: 'object',
      properties: {},
    },
  },
];

server.setRequestHandler(ListToolsRequestSchema, async () => ({ tools }));

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  const { name, arguments: args } = request.params;

  switch (name) {
    case 'query_database':
      // Implementation would query PostgreSQL
      return { content: [{ type: 'text', text: 'Query executed' }] };
    case 'create_record':
      // Implementation would call PostgREST
      return { content: [{ type: 'text', text: 'Record created' }] };
    case 'upload_file':
      // Implementation would upload to MinIO
      return { content: [{ type: 'text', text: 'File uploaded' }] };
    case 'auth_user':
      return { content: [{ type: 'text', text: 'User info' }] };
    default:
      throw new Error(`Unknown tool: ${name}`);
  }
});

async function main() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error('Easyploy MCP server running');
}

main().catch(console.error);
